import { useEffect, useState } from 'react'

import {
  CheckCircle as CheckCircleIcon,
  FitnessCenter as FitnessCenterIcon,
} from '@mui/icons-material'
import {
  Box,
  Chip,
  CircularProgress,
  Container,
  LinearProgress,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Paper,
  Typography,
} from '@mui/material'

import { getTodaysExecutionsByPlanIds } from '@/api/trainingExecutions'
import { getTrainingPlans } from '@/api/trainingPlans'
import { LoginButton } from '@/components/LoginButton'
import { PlanExecutionButton } from '@/components/PlanExecutionButton'
import { useAuth } from '@/contexts/AuthContext'
import type { TrainingPlan } from '@/types/database'
import { getTodaysPlans, getWeekDayLabel } from '@/utils/schedule'
import { renderUnit } from '@/utils/unit-utils'

export function HomePage() {
  const { user } = useAuth()
  const [todaysPlans, setTodaysPlans] = useState<TrainingPlan[]>([])
  const [todayExecutionMap, setTodayExecutionMap] = useState<Map<number, number>>(new Map())
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (user) {
      loadTodaysPlans()
    }
  }, [user])

  async function loadTodaysPlans() {
    try {
      setLoading(true)
      const plans = await getTrainingPlans()
      const filtered = getTodaysPlans(plans)
      setTodaysPlans(filtered)

      if (filtered.length > 0) {
        const planIds = filtered.map((p) => p.id)
        const executions = await getTodaysExecutionsByPlanIds(planIds)
        const map = new Map<number, number>()
        for (const exec of executions) {
          map.set(exec.plan_id, (map.get(exec.plan_id) ?? 0) + exec.unit_count)
        }
        setTodayExecutionMap(map)
      }
    } catch {
      // Silently fail
    } finally {
      setLoading(false)
    }
  }

  const todayStr = new Date().toLocaleDateString('ko-KR', {
    month: 'long',
    day: 'numeric',
    weekday: 'short',
  })

  const sortedPlans = [...todaysPlans].sort((a, b) => {
    const aAchieved = (todayExecutionMap.get(a.id) ?? 0) >= a.unit_amount ? 1 : 0
    const bAchieved = (todayExecutionMap.get(b.id) ?? 0) >= b.unit_amount ? 1 : 0
    return aAchieved - bAchieved
  })

  return (
    <Container maxWidth="sm">
      <Box sx={{ my: 4, textAlign: 'center' }}>
        {user ? (
          <>
            {/* Today's Training Section */}
            <Paper elevation={3} sx={{ p: 3, textAlign: 'left' }}>
              <Typography variant="h6" gutterBottom>
                📅 오늘의 훈련 ({todayStr})
              </Typography>
              {loading ? (
                <Box sx={{ display: 'flex', justifyContent: 'center', py: 2 }}>
                  <CircularProgress size={24} />
                </Box>
              ) : sortedPlans.length === 0 ? (
                <Typography color="text.secondary" sx={{ py: 2, textAlign: 'center' }}>
                  오늘 예정된 훈련이 없습니다
                </Typography>
              ) : (
                <List disablePadding>
                  {sortedPlans.map((plan) => {
                    const todayUnits = todayExecutionMap.get(plan.id) ?? 0
                    const isAchieved = todayUnits >= plan.unit_amount
                    const progress = Math.min(100, (todayUnits / plan.unit_amount) * 100)

                    return (
                      <ListItem
                        key={plan.id}
                        sx={{ flexDirection: 'column', alignItems: 'stretch', px: 0 }}
                      >
                        <Box sx={{ display: 'flex', alignItems: 'center', width: '100%' }}>
                          <ListItemIcon sx={{ minWidth: 40 }}>
                            {isAchieved ? (
                              <CheckCircleIcon color="success" />
                            ) : (
                              <FitnessCenterIcon color="primary" />
                            )}
                          </ListItemIcon>
                          <ListItemText
                            primary={plan.name}
                            secondary={`${plan.unit_amount} ${renderUnit(plan.unit_name)}`}
                          />
                          <Chip
                            label={
                              plan.schedule_type === 'daily'
                                ? '매일'
                                : plan.schedule_days?.map(getWeekDayLabel).join(', ')
                            }
                            size="small"
                            variant="outlined"
                          />
                          <Box sx={{ marginLeft: '.4rem' }}>
                            <PlanExecutionButton plan={plan} variant="contained" />
                          </Box>
                        </Box>
                        {todayUnits > 0 && (
                          <Box sx={{ pl: 5, pr: 1, pb: 0.5 }}>
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                              <LinearProgress
                                variant="determinate"
                                value={progress}
                                color={isAchieved ? 'success' : 'primary'}
                                sx={{ flex: 1, borderRadius: 1 }}
                              />
                              <Typography
                                variant="caption"
                                color={isAchieved ? 'success.main' : 'text.secondary'}
                                sx={{ whiteSpace: 'nowrap' }}
                              >
                                {isAchieved
                                  ? `${todayUnits} 달성 ✓`
                                  : `${todayUnits} / ${plan.unit_amount}`}
                              </Typography>
                            </Box>
                          </Box>
                        )}
                      </ListItem>
                    )
                  })}
                </List>
              )}
            </Paper>
          </>
        ) : (
          <Paper elevation={3} sx={{ p: 3, mt: 3 }}>
            <Typography variant="body1" sx={{ mb: 3 }}>
              시작하려면 로그인하세요
            </Typography>
            <LoginButton />
          </Paper>
        )}
      </Box>
    </Container>
  )
}
